mapper.select:
	  SELECT COUNT(*)
        FROM ORDERS
        WHERE ORDER_DATE >= #{startDate}
          AND ORDER_DATE < #{nextMonthStartDate}
          AND ORDER_CANCEL_YN = 'N'

SELECT NVL(SUM(ORDER_TOTAL_PRICE), 0)
       FROM ORDERS
       WHERE ORDER_DATE >= #{startDate}
         AND ORDER_DATE < #{nextMonthStartDate}
         AND ORDER_CANCEL_YN = 'N'

SELECT COUNT(*)
      FROM ORDERS
      WHERE ORDER_DATE >= #{startDate}
        AND ORDER_DATE < #{nextMonthStartDate}
        AND ORDER_CANCEL_YN = 'N'

SELECT * FROM ( SELECT ROWNUM AS RNUM, T1.* FROM ( SELECT O.ORDER_TOTAL_PRICE, O.ORDER_DATE, ( SELECT MIN(C.COMPANY_NAME) FROM ORDER_DETAIL OD JOIN PRODUCT P ON OD.PRODUCT_ID = P.PRODUCT_ID JOIN COMPANY C ON P.COMPANY_CODE = C.COMPANY_CODE WHERE OD.ORDER_ID = O.ORDER_ID ) AS COMPANY_NAME
FROM ORDERS O
O.ORDER_CANCEL_YN = 'N'
AND O.ORDER_DATE BETWEEN #{startDate} AND #{endDate}
ORDER BY O.ORDER_DATE DESC ) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*) FROM ORDERS O
O.ORDER_CANCEL_YN = 'N'
AND O.ORDER_DATE BETWEEN #{startDate} AND #{endDate}

SELECT NVL(SUM(ORDER_TOTAL_PRICE), 0) FROM ORDERS O
O.ORDER_CANCEL_YN = 'N'
AND O.ORDER_DATE BETWEEN #{startDate} AND #{endDate}

